+/**
+ * Run a task-producing function, retrying it up to `n` additional times after
+ * rejection. The final rejection reason is preserved unchanged.
+ */
+export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
+  const attempt = (remaining: number): Task<T, E> =>
+    fn().orElse((error) => (remaining > 0 ? attempt(remaining - 1) : Task.reject<T, E>(error)));
+  return attempt(Math.max(0, Math.floor(n)));
+}
